Wire together client.ts, actor.ts, config.ts, and inbox.ts into the extension entry point.

## File to modify
- packages/extension/src/index.ts (currently a skeleton from kg9.1)

## Implementation

```typescript
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { loadConfig } from "./config.ts";
import { defaultBridgeConfig, BridgeClientError } from "./types.ts";
import { CCCCBridgeClient } from "./client.ts";
import { ensureRegistered } from "./actor.ts";
import { InboxPoller } from "./inbox.ts";
import { join } from "node:path";
import { homedir } from "node:os";

const STATE_FILE = join(homedir(), ".pi", "agent", "extensions", "cccc-bridge-state.json");

export default function (pi: ExtensionAPI) {
  let client: CCCCBridgeClient | null = null;
  let poller: InboxPoller | null = null;

  pi.on("session_start", async (_event, ctx) => {
    const config = loadConfig();
    if (!config.groupId) return; // inert when unconfigured

    try {
      // Connect to daemon
      client = new CCCCBridgeClient();
      await client.connect(defaultBridgeConfig());

      // Register actor (idempotent)
      const actorId = await ensureRegistered(client, config, config.groupId, STATE_FILE);

      // Start polling
      poller = new InboxPoller({
        client,
        groupId: config.groupId,
        actorId,
        pollIntervalMs: config.pollIntervalMs,
        pi,
      });
      poller.start();

      if (ctx.hasUI) {
        ctx.ui.setStatus("cccc", "connected");
        ctx.ui.notify("CCCC bridge connected", "info");
      }
    } catch (err) {
      // Graceful degradation — session works without CCCC
      console.error("[cccc-bridge] Failed to connect:", err);
      if (ctx.hasUI) {
        const msg = err instanceof BridgeClientError ? err.message : "Failed to connect to CCCC daemon";
        ctx.ui.notify(`CCCC bridge: ${msg}`, "error");
        ctx.ui.setStatus("cccc", "disconnected");
      }
    }
  });

  pi.on("session_shutdown", async () => {
    poller?.stop();
    poller = null;
    client?.disconnect();
    client = null;
  });
}
```

## Key behaviors
1. Inert when CCCC_GROUP_ID is not set (no connection, no errors)
2. Graceful degradation: if daemon unreachable, notify user and continue without CCCC
3. ctx.ui.setStatus shows "connected" or "disconnected" in footer
4. ctx.hasUI guard before any UI calls (supports print/json mode)
5. session_shutdown stops poller and disconnects client
6. State file path: ~/.pi/agent/extensions/cccc-bridge-state.json (same as actor.ts uses)

## Testing
This is integration wiring — test that the factory function:
1. Returns without error when CCCC_GROUP_ID is empty (inert)
2. Calls client.connect and poller.start when configured
3. Handles connection failure gracefully (catches error, calls ctx.ui.notify)
4. session_shutdown stops poller and disconnects client

Mock all dependencies: CCCCBridgeClient, ensureRegistered, InboxPoller.
Use vi.mock or dependency injection pattern.
